import json
from collections import defaultdict

class QueryParser:
    """
    A custom parser for a simplified query language.
    Supports filtering, aggregation, and joining of datasets.
    """

    def __init__(self, query_string):
        self.query_string = query_string
        self.query_data = None
        self.datasets = {}
        self.errors = []

    def parse(self):
        """
        Parses the query string into a structured format.
        """
        try:
            self.query_data = json.loads(self.query_string)
        except json.JSONDecodeError as e:
            self.errors.append(f"Invalid JSON: {e}")
            return False
        return True

    def validate(self):
        """
        Validates the parsed query data.
        """
        if not self.query_data:
            self.errors.append("Query data is empty after parsing.")
            return False

        if "datasets" not in self.query_data:
            self.errors.append("Missing 'datasets' key in query.")
            return False

        for dataset_name, dataset_data in self.query_data["datasets"].items():
            if not isinstance(dataset_data, dict):
                self.errors.append(f"Invalid dataset format for {dataset_name}.  Expected a dictionary.")
                return False

    def execute(self):
        """
        Executes the query and returns the result.
        """
        if not self.query_data or not self.query_data["datasets"]:
            return {}  # Return empty dict if no datasets

        # Initialize datasets
        for dataset_name, dataset_data in self.query_data["datasets"].items():
            self.datasets[dataset_name] = dataset_data

        # Build the query structure
        query_type = self.query_data.get("type", "aggregate")
        filters = self.query_data.get("filters", [])
        aggregations = self.query_data.get("aggregations", [])
        join_conditions = self.query_data.get("joins", [])

        # Execute based on query type
        if query_type == "aggregate":
            result = self._aggregate()
        elif query_type == "join":
            result = self._join()
        else:
            self.errors.append(f"Unsupported query type: {query_type}")
            return {}

        return result

    def _aggregate(self):
        """
        Executes an aggregation query.
        """
        result = {}
        for aggregation in aggregations:
            field = aggregation["field"]
            function = aggregation["function"]
            dataset_name = aggregation["dataset"]
            if dataset_name not in self.datasets:
                self.errors.append(f"Dataset '{dataset_name}' not found.")
                return {}

            data = self.datasets[dataset_name]
            if function == "sum":
                result[field] = sum(data.get(field, []) or [0])
            elif function == "avg":
                total = 0
                count = 0
                for value in data.get(field, []):
                    total += value
                    count += 1
                if count > 0:
                    result[field] = total / count
                else:
                    result[field] = 0
            else:
                self.errors.append(f"Unsupported aggregation function: {function}")
                return {}
        return result

    def _join(self):
